# Complex type {http://www.witsml.org/schemas/1series}cs_location with content type ELEMENT_ONLY
class cs_location (pyxb.binding.basis.complexTypeDefinition):
    """WITSML Location Component Schema
			This is a location that is expressed in terms of 2D coordinates. 
			In order that the location be understood, the coordinate reference system (CRS) 
			must be known. The survey location is given by a pair of tagged values. 
			The pairs may be: 
			(1) latitude/longitude, 
			(2) easting/northing, 
			(3) westing/southing, 
			(4) projectedX/projectedY, or 
			(5) localX/localY. 
			The appropriate pair must be chosen for the data."""
    _TypeDefinition = None
    _ContentTypeTag = pyxb.binding.basis.complexTypeDefinition._CT_ELEMENT_ONLY
    _Abstract = False
    _ExpandedName = pyxb.namespace.ExpandedName(Namespace, 'cs_location')
    _XSDLocation = pyxb.utils.utility.Location('cs_location.xsd', 21, 1)
    _ElementMap = {}
    _AttributeMap = {}
    # Base type is pyxb.binding.datatypes.anyType
    
    # Element {http://www.witsml.org/schemas/1series}wellCRS uses Python identifier wellCRS
    __wellCRS = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'wellCRS'), 'wellCRS', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieswellCRS', False, pyxb.utils.utility.Location('cs_location.xsd', 37, 3), )

    
    wellCRS = property(__wellCRS.value, __wellCRS.set, None, 'A pointer to the wellCRS that defines the CRS for the coordinates. \n\t\t\t\t\tWhile optional, it is strongly recommended that this be specified.')

    
    # Element {http://www.witsml.org/schemas/1series}latitude uses Python identifier latitude
    __latitude = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'latitude'), 'latitude', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieslatitude', False, pyxb.utils.utility.Location('cs_location.xsd', 51, 5), )

    
    latitude = property(__latitude.value, __latitude.set, None, 'The latitude with north being positive.')

    
    # Element {http://www.witsml.org/schemas/1series}longitude uses Python identifier longitude
    __longitude = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'longitude'), 'longitude', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieslongitude', False, pyxb.utils.utility.Location('cs_location.xsd', 56, 5), )

    
    longitude = property(__longitude.value, __longitude.set, None, 'The longitude with east being positive.')

    
    # Element {http://www.witsml.org/schemas/1series}easting uses Python identifier easting
    __easting = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'easting'), 'easting', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieseasting', False, pyxb.utils.utility.Location('cs_location.xsd', 66, 5), )

    
    easting = property(__easting.value, __easting.set, None, 'The projected coordinate with east being positive. \n\t\t\t\t\t\t\tThis is the most common type of projected coordinates. \n\t\t\t\t\t\t\tUTM coordinates are expressed in Easting and Northing.')

    
    # Element {http://www.witsml.org/schemas/1series}northing uses Python identifier northing
    __northing = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'northing'), 'northing', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriesnorthing', False, pyxb.utils.utility.Location('cs_location.xsd', 73, 5), )

    
    northing = property(__northing.value, __northing.set, None, 'The projected coordinate with north being positive. \n\t\t\t\t\t\t\tThis is the most common type of projected coordinates. \n\t\t\t\t\t\t\tUTM coordinates are expressed in Easting and Northing.')

    
    # Element {http://www.witsml.org/schemas/1series}westing uses Python identifier westing
    __westing = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'westing'), 'westing', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieswesting', False, pyxb.utils.utility.Location('cs_location.xsd', 85, 5), )

    
    westing = property(__westing.value, __westing.set, None, 'The projected coordinate with west being positive. \n\t\t\t\t\t\t\tThe positive directions are reversed from the usual Easting and Northing values. \n\t\t\t\t\t\t\tThese values are generally located in the southern hemisphere, \n\t\t\t\t\t\t\tmost notably in South Africa and Australia.')

    
    # Element {http://www.witsml.org/schemas/1series}southing uses Python identifier southing
    __southing = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'southing'), 'southing', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriessouthing', False, pyxb.utils.utility.Location('cs_location.xsd', 93, 5), )

    
    southing = property(__southing.value, __southing.set, None, 'The projected coordinate with south being positive. \n\t\t\t\t\t\t\tThe positive directions are reversed from the usual Easting and Northing values. \n\t\t\t\t\t\t\tThese values are generally located in the southern hemisphere, \n\t\t\t\t\t\t\tmost notably in South Africa and Australia.')

    
    # Element {http://www.witsml.org/schemas/1series}projectedX uses Python identifier projectedX
    __projectedX = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'projectedX'), 'projectedX', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriesprojectedX', False, pyxb.utils.utility.Location('cs_location.xsd', 106, 5), )

    
    projectedX = property(__projectedX.value, __projectedX.set, None, 'The projected X coordinate with the positive direction unknown.\n\t\t\t\t\t\t\tProjectedX and ProjectedY are used when it is not \n\t\t\t\t\t\t\tknown what the meaning of the coordinates is. If the meaning is known, \n\t\t\t\t\t\t\tthe Easting/Northing or Westing/Southing should be used. Use of this pair \n\t\t\t\t\t\t\timplies a lack of knowledge on the part of the sender.')

    
    # Element {http://www.witsml.org/schemas/1series}projectedY uses Python identifier projectedY
    __projectedY = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'projectedY'), 'projectedY', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriesprojectedY', False, pyxb.utils.utility.Location('cs_location.xsd', 115, 5), )

    
    projectedY = property(__projectedY.value, __projectedY.set, None, 'The projected Y coordinate with the positive direction unknown.\n\t\t\t\t\t\t\tProjectedX and ProjectedY are used when it is not \n\t\t\t\t\t\t\tknown what the meaning of the coordinates is. If the meaning is known, \n\t\t\t\t\t\t\tthe Easting/Northing or Westing/Southing should be used. Use of this pair \n\t\t\t\t\t\t\timplies a lack of knowledge on the part of the sender.')

    
    # Element {http://www.witsml.org/schemas/1series}localX uses Python identifier localX
    __localX = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'localX'), 'localX', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieslocalX', False, pyxb.utils.utility.Location('cs_location.xsd', 129, 5), )

    
    localX = property(__localX.value, __localX.set, None, 'The local (engineering) X coordinate. \n\t\t\t\t\t\t\tThe CRS will define the orientation of the axis.')

    
    # Element {http://www.witsml.org/schemas/1series}localY uses Python identifier localY
    __localY = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'localY'), 'localY', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1serieslocalY', False, pyxb.utils.utility.Location('cs_location.xsd', 135, 5), )

    
    localY = property(__localY.value, __localY.set, None, 'The local (engineering) Y coordinate. \n\t\t\t\t\t\t\tThe CRS will define the orientation of the axis.')

    
    # Element {http://www.witsml.org/schemas/1series}original uses Python identifier original
    __original = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'original'), 'original', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriesoriginal', False, pyxb.utils.utility.Location('cs_location.xsd', 143, 3), )

    
    original = property(__original.value, __original.set, None, 'Flag indicating (if "true" or "1") that this pair of values was \n\t\t\t\t\tthe original data given for the location. If the pair of values was \n\t\t\t\t\tcalculated from an original pair of values, this flag should be "false" (or "0"), \n\t\t\t\t\tor not present.')

    
