    __description = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'description'), 'description', '__httpwww_witsml_orgschemas1series_cs_location_httpwww_witsml_orgschemas1seriesdescription', False, pyxb.utils.utility.Location('cs_location.xsd', 151, 3), )

    
