    __magXAxialCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'magXAxialCorUsed'), 'magXAxialCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesmagXAxialCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 175, 3), )

    
