    # Element {http://www.witsml.org/schemas/1series}sagCorUsed uses Python identifier sagCorUsed
    __sagCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'sagCorUsed'), 'sagCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriessagCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 181, 3), )

    
