    # Element {http://www.witsml.org/schemas/1series}magDrlstrCorUsed uses Python identifier magDrlstrCorUsed
    __magDrlstrCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'magDrlstrCorUsed'), 'magDrlstrCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesmagDrlstrCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 187, 3), )

    
    magDrlstrCorUsed = property(__magDrlstrCorUsed.value, __magDrlstrCorUsed.set, None, 'Was a drillstring magnetism correction applied to survey computation?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").')

    
    # Element {http://www.witsml.org/schemas/1series}infieldRefCorUsed uses Python identifier infieldRefCorUsed
    __infieldRefCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'infieldRefCorUsed'), 'infieldRefCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesinfieldRefCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 193, 3), )

    
    infieldRefCorUsed = property(__infieldRefCorUsed.value, __infieldRefCorUsed.set, None, 'Was an In Field Referencing (IFR) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tAn IFR survey measures the strength and direction of the Earth\'s magnetic field over the area of interest. \n\t\t\t\t\tBy taking a geomagnetic modelled values away \n\t\t\t\t\tfrom these field survey results, we are left with a local crustal correction, \n\t\t\t\t\twhich since it is assumed geological in nature, only varies over geological timescales.  \n\t\t\t\t\tFor MWD survey operations, these corrections are applied in addition to the geomagnetic model \n\t\t\t\t\tto provide accurate knowledge of the local magnetic field and hence to improve the \n\t\t\t\t\taccuracy of MWD magnetic azimuth measurements.')

    
    # Element {http://www.witsml.org/schemas/1series}interpolatedInfieldRefCorUsed uses Python identifier interpolatedInfieldRefCorUsed
    __interpolatedInfieldRefCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'interpolatedInfieldRefCorUsed'), 'interpolatedInfieldRefCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesinterpolatedInfieldRefCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 207, 3), )

    
    interpolatedInfieldRefCorUsed = property(__interpolatedInfieldRefCorUsed.value, __interpolatedInfieldRefCorUsed.set, None, 'Was an Interpolated In Field Referencing (IIFR) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tInterpolated In Field Referencing measures the diurnal Earth magnetic field variations resulting from electrical \n\t\t\t\t\tcurrents in the ionosphere and effects of magnetic storms hitting the Earth. It increases again the accuracy \n\t\t\t\t\tof the magnetic azimuth measurement.')

    
    # Element {http://www.witsml.org/schemas/1series}inHoleRefCorUsed uses Python identifier inHoleRefCorUsed
    __inHoleRefCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'inHoleRefCorUsed'), 'inHoleRefCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesinHoleRefCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 217, 3), )

    
    inHoleRefCorUsed = property(__inHoleRefCorUsed.value, __inHoleRefCorUsed.set, None, 'Was an In Hole Referencing (IHR) correction applied to the inclination and/or azimuth values?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tIn-Hole Referencing essentially involves comparing gyro surveys to MWD surveys in a tangent \n\t\t\t\t\tsection of a well. Once a small part of a tangent section has been drilled and surveyed using an \n\t\t\t\t\tMWD tool, then an open hole (OH) gyro is run. By comparing the Gyro surveys to the MWD \n\t\t\t\t\tsurveys a correction can be calculated for the MWD. This correction is then assumed as valid \n\t\t\t\t\tfor the rest of the tangent section allowing to have a near gyro accuracy for the whole section, \n\t\t\t\t\ttherefore reducing the ellipse of uncertainty (EOU) size.')

    
    # Element {http://www.witsml.org/schemas/1series}axialMagInterferenceCorUsed uses Python identifier axialMagInterferenceCorUsed
    __axialMagInterferenceCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'axialMagInterferenceCorUsed'), 'axialMagInterferenceCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesaxialMagInterferenceCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 230, 3), )

    
    axialMagInterferenceCorUsed = property(__axialMagInterferenceCorUsed.value, __axialMagInterferenceCorUsed.set, None, 'Was an Axial Magnetic Interference (AMI) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tMost of the BHAs used to drill wells include an MWD tool. An MWD is a magnetic survey tool and as \n\t\t\t\t\tsuch suffer from magnetic interferences from a wide variety of sources. Magnetic interferences can be \n\t\t\t\t\tcategorized into axial and radial type interferences. \n\t\t\t\t\tAxial interferences are mainly the result of magnetic poles from the drill string steel components \n\t\t\t\t\tlocated below and above the MWD tool. Radial interferences are numerous. \n\t\t\t\t\tTherefore, there is a risk that magXAxialCorUsed includes both Axial and radial corrections.')

    
    # Element {http://www.witsml.org/schemas/1series}cosagCorUsed uses Python identifier cosagCorUsed
    __cosagCorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'cosagCorUsed'), 'cosagCorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriescosagCorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 243, 3), )

    
    cosagCorUsed = property(__cosagCorUsed.value, __cosagCorUsed.set, None, 'WWas a Cosag Correction applied to the azimuth values?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tThe BHA Sag Correction is the same as the Sag Correction except it includes the horizontal \n\t\t\t\t\tmisalignment (Cosag).')

    
    # Element {http://www.witsml.org/schemas/1series}MSACorUsed uses Python identifier MSACorUsed
    __MSACorUsed = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'MSACorUsed'), 'MSACorUsed', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesMSACorUsed', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 252, 3), )

    
