    __magDipAngleReference = pyxb.binding.content.ElementDeclaration(pyxb.namespace.ExpandedName(Namespace, 'magDipAngleReference'), 'magDipAngleReference', '__httpwww_witsml_orgschemas1series_cs_trajectoryStation_httpwww_witsml_orgschemas1seriesmagDipAngleReference', False, pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 272, 3), )

    
