cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'name'), kindString, scope=cs_nameTag, documentation='The physical identification string of the equipment tag.', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 26, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'numberingScheme'), NameTagNumberingScheme, scope=cs_nameTag, documentation='The format or encoding specification of the equipment tag. \n\t\t\t\t\tThe tag may contain may different pieces of information and knowledge of that \n\t\t\t\t\tinformation is inherent in the specification. \n\t\t\t\t\tThe "identification string" is a mandatory part of the information in a tag.', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 31, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'technology'), NameTagTechnology, scope=cs_nameTag, documentation="Identifies the general type of identifier on an\n\t\t\t\t\titem.  If multiple identifiers exist on an item, a separate\n\t\t\t\t\tdescription set for each identifier should be created.  \n\t\t\t\t\tFor example, a joint of casing may have a barcode label on it along with a\n\t\t\t\t\tpainted-on code and an RFID tag attached or embedded into the coupling.  The\n\t\t\t\t\tbarcode label may in turn be an RFID equipped label. This particular\n\t\t\t\t\tscenario would require populating five nameTags to fully describe\n\t\t\t\t\tand decode all the possible identifiers as follows:\n\t\t\t\t\t'tagged' - RFID tag embedded in the coupling,\n\t\t\t\t\t'label'  - Serial number printed on the label,\n\t\t\t\t\t'tagged' - RFID tag embedded into the label,\n\t\t\t\t\t'label'  - Barcode printed on the label,\n\t\t\t\t\t'painted'- Mill number painted on the pipe body.", location=pyxb.utils.utility.Location('cs_nameTag.xsd', 39, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'location'), NameTagLocation, scope=cs_nameTag, documentation="An indicator of where the tag is attached to the item.\n\t\t\t\t\tThis is used to assist the user in finding where an identifier is\n\t\t\t\t\tlocated on an item.  This optional field also helps to differentiate\n\t\t\t\t\twhere an identifier is located when multiple identifiers exist on an\n\t\t\t\t\titem. Most downhole components have a box (female thread) and pin (male\n\t\t\t\t\tthread) end as well as a pipe body in between the ends.\n\t\t\t\t\tWhere multiple identifiers are used on an item, it is convenient to have\n\t\t\t\t\ta reference as to which end, or somewhere in the middle, an identifier may\n\t\t\t\t\tbe closer to. Some items may have an identifier on a non-standard location,\n\t\t\t\t\tsuch as on the arm of a hole opener.  'other', by exclusion, tells a user to\n\t\t\t\t\tlook elsewhere than on the body or near the ends of an item.  Most\n\t\t\t\t\tnon-downhole tools will use either 'body', 'other' or not specified\n\t\t\t\t\tas the location tends to lose value with smaller or non threaded items.", location=pyxb.utils.utility.Location('cs_nameTag.xsd', 56, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'installationDate'), timestamp, scope=cs_nameTag, documentation='When the tag was installed in or on the item.  ', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 73, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'installationCompany'), nameString, scope=cs_nameTag, documentation='The name of the company that installed the tag.  ', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 78, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'mountingCode'), kindString, scope=cs_nameTag, documentation='Reference to a manufacturers or installers installation \n\t\t\t\t\tdescription, code, or method.  ', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 83, 3)))

cs_nameTag._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'comment'), commentString, scope=cs_nameTag, documentation='A comment or remark about the tag.', location=pyxb.utils.utility.Location('cs_nameTag.xsd', 89, 3)))

