cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'sagCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was a bottom hole assembly sag correction applied to the survey computation?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 181, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'magDrlstrCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was a drillstring magnetism correction applied to survey computation?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 187, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'infieldRefCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was an In Field Referencing (IFR) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tAn IFR survey measures the strength and direction of the Earth\'s magnetic field over the area of interest. \n\t\t\t\t\tBy taking a geomagnetic modelled values away \n\t\t\t\t\tfrom these field survey results, we are left with a local crustal correction, \n\t\t\t\t\twhich since it is assumed geological in nature, only varies over geological timescales.  \n\t\t\t\t\tFor MWD survey operations, these corrections are applied in addition to the geomagnetic model \n\t\t\t\t\tto provide accurate knowledge of the local magnetic field and hence to improve the \n\t\t\t\t\taccuracy of MWD magnetic azimuth measurements.', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 193, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'interpolatedInfieldRefCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was an Interpolated In Field Referencing (IIFR) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tInterpolated In Field Referencing measures the diurnal Earth magnetic field variations resulting from electrical \n\t\t\t\t\tcurrents in the ionosphere and effects of magnetic storms hitting the Earth. It increases again the accuracy \n\t\t\t\t\tof the magnetic azimuth measurement.', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 207, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'inHoleRefCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was an In Hole Referencing (IHR) correction applied to the inclination and/or azimuth values?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tIn-Hole Referencing essentially involves comparing gyro surveys to MWD surveys in a tangent \n\t\t\t\t\tsection of a well. Once a small part of a tangent section has been drilled and surveyed using an \n\t\t\t\t\tMWD tool, then an open hole (OH) gyro is run. By comparing the Gyro surveys to the MWD \n\t\t\t\t\tsurveys a correction can be calculated for the MWD. This correction is then assumed as valid \n\t\t\t\t\tfor the rest of the tangent section allowing to have a near gyro accuracy for the whole section, \n\t\t\t\t\ttherefore reducing the ellipse of uncertainty (EOU) size.', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 217, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'axialMagInterferenceCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was an Axial Magnetic Interference (AMI) correction applied to the azimuth value?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tMost of the BHAs used to drill wells include an MWD tool. An MWD is a magnetic survey tool and as \n\t\t\t\t\tsuch suffer from magnetic interferences from a wide variety of sources. Magnetic interferences can be \n\t\t\t\t\tcategorized into axial and radial type interferences. \n\t\t\t\t\tAxial interferences are mainly the result of magnetic poles from the drill string steel components \n\t\t\t\t\tlocated below and above the MWD tool. Radial interferences are numerous. \n\t\t\t\t\tTherefore, there is a risk that magXAxialCorUsed includes both Axial and radial corrections.', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 230, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'cosagCorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='WWas a Cosag Correction applied to the azimuth values?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").\n\t\t\t\t\tThe BHA Sag Correction is the same as the Sag Correction except it includes the horizontal \n\t\t\t\t\tmisalignment (Cosag).', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 243, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'MSACorUsed'), logicalBoolean, scope=cs_trajectoryStation, documentation='Was a correction applied to the survey due to a \n\t\t\t\t\tMulti-Station Analysis process?  \n\t\t\t\t\tValues are "true" (or "1") and "false" (or "0").', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 252, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'gravTotalFieldReference'), accelerationLinearMeasure, scope=cs_trajectoryStation, documentation='Gravitational field theoretical/reference value.\n\t\t\t\t\t', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 260, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'magTotalFieldReference'), magneticInductionMeasure, scope=cs_trajectoryStation, documentation='Geomagnetic field theoretical/reference value.\n\t\t\t\t\t', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 266, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'magDipAngleReference'), planeAngleMeasure, scope=cs_trajectoryStation, documentation='Magnetic dip angle theoretical/reference value.\n\t\t\t\t\t', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 272, 3)))

cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'magModelUsed'), nameString, scope=cs_trajectoryStation, documentation='Geomagnetic model used.\n\t\t\t\t\t', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 278, 3)))

