cs_trajectoryStation._AddElement(pyxb.binding.basis.element(pyxb.namespace.ExpandedName(Namespace, 'statusTrajStation'), TrajStationStatus, scope=cs_trajectoryStation, documentation='Status of the station.  ', location=pyxb.utils.utility.Location('cs_trajectoryStation.xsd', 296, 3)))

